const urls = $json.urls || [];
if (!Array.isArray(urls) || urls.length === 0) {
  throw new Error('urls 배열이 비어 있습니다. body.urls에 URL 배열을 전달하세요.');
}
return urls.map((u) => ({ json: { url: u, targetLanguage: $json.targetLanguage || 'ko' } }));

// Handle success + API/network errors
if ($json.error) {
  const src = $item(0).$node['Explode URLs'].json.url;
  return [{ json: { source_url: src, ok: false, error_type: 'upstage_or_network', status: $json.error?.statusCode || $json.statusCode || null, error_message: $json.error?.message || $json.message || 'Unknown error', retry_after: $json.error?.response?.headers?.['retry-after'] || null } }];
}
const content = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch (e) { parsed = { raw: content }; }
return [{ json: { source_url: $item(0).$node['Explode URLs'].json.url, ok: true, ...parsed } }];

const all = $input.all().map(i => i.json);
const success = all.filter(x => x.ok !== false).length;
const failed = all.length - success;
return [{ json: { ok: failed === 0, count: all.length, success, failed, summaries: all } }];

const lang = $json.targetLanguage || 'ko';
const url = $json.url || 'n/a';
const content = String($json.body || $json.data || $json.content || '').slice(0,12000);
const payload = {
  model:'solar-pro2',
  temperature:0.2,
  response_format:{
    type:'json_schema',
    json_schema:{
      name:'paper_summary',
      schema:{
        type:'object',
        properties:{
          title:{type:'string'}, one_line:{type:'string'}, problem:{type:'string'}, method:{type:'string'},
          results:{type:'string'}, limitations:{type:'string'}, tags:{type:'array',items:{type:'string'}}, action_items:{type:'array',items:{type:'string'}}
        },
        required:['title','one_line','problem','method','results','limitations','tags','action_items'],
        additionalProperties:false
      }
    }
  },
  messages:[
    {role:'system', content:'너는 논문 리뷰 어시스턴트다. 입력 텍스트를 읽고 '+lang+'로만 답해라. 과장 금지. 수치/조건은 최대한 보존하라.'},
    {role:'user', content:'다음 논문 페이지/본문을 분석해 구조화 요약 JSON으로 만들어줘.\n원본 URL: '+url+'\n\n본문:\n'+content}
  ]
};
return [{json:{...$json, upstage_payload:payload}}];
